import re
import unicodedata

def slugify(s: str) -> str:
    """Convert string to lowercase hyphenated slug."""
    s = unicodedata.normalize("NFKD", s).encode("ascii", "ignore").decode("ascii")
    s = s.lower()
    s = re.sub(r"[^\w\s-]", "", s)
    s = re.sub(r"[\s_]+", "-", s)
    s = re.sub(r"-+", "-", s)
    return s.strip("-")

def truncate_middle(s: str, n: int) -> str:
    """Return s truncated to n chars keeping both ends joined by '…' if len(s)>n."""
    if len(s) <= n:
        return s
    if n <= 1:
        return "…"
    keep = n - 1
    left = (keep + 1) // 2
    right = keep // 2
    return s[:left] + "…" + s[len(s) - right:]

def word_count(s: str) -> int:
    """Return the number of whitespace-delimited words in s."""
    return len(s.split())
```


