"""
time-utils — time/date helper functions

Spec:
  parse_hms(s):
    - Format: 'H:M:S' (all three components required)
    - Components must be non-negative integers
    - Raises ValueError on wrong component count, non-integer parts, or negative values
    - '1:30' raises ValueError (missing seconds)

  humanize_secs(n):
    - n must be >= 0 (negative raises ValueError)
    - Always emits all three components, including zeros: '0h 0m 0s', '1h 2m 3s'

  is_leap(year):
    - Gregorian rule: divisible by 4, except centuries, except 400-year centuries
    - year <= 0 raises ValueError (no year 0 in proleptic Gregorian; negative unsupported)
"""


def parse_hms(s: str) -> int:
    parts = s.split(":")
    if len(parts) != 3:
        raise ValueError(f"Expected H:M:S, got {s!r}")
    try:
        h, m, sec = (int(p) for p in parts)
    except ValueError:
        raise ValueError(f"Non-integer component in {s!r}")
    if h < 0 or m < 0 or sec < 0:
        raise ValueError(f"Negative component in {s!r}")
    return h * 3600 + m * 60 + sec


def humanize_secs(n: int) -> str:
    if n < 0:
        raise ValueError(f"n must be >= 0, got {n}")
    h = n // 3600
    m = (n % 3600) // 60
    s = n % 60
    return f"{h}h {m}m {s}s"


def is_leap(year: int) -> bool:
    if year <= 0:
        raise ValueError(f"year must be >= 1, got {year}")
    return year % 4 == 0 and (year % 100 != 0 or year % 400 == 0)


# --- tests ---

import unittest


class TestParseHms(unittest.TestCase):
    def test_normal(self):
        self.assertEqual(parse_hms("1:02:03"), 3723)

    def test_zeros(self):
        self.assertEqual(parse_hms("0:0:0"), 0)

    def test_missing_seconds(self):
        with self.assertRaises(ValueError):
            parse_hms("1:30")

    def test_extra_component(self):
        with self.assertRaises(ValueError):
            parse_hms("1:2:3:4")

    def test_non_integer(self):
        with self.assertRaises(ValueError):
            parse_hms("1:2:x")

    def test_large(self):
        self.assertEqual(parse_hms("23:59:59"), 86399)


class TestHumanizeSecs(unittest.TestCase):
    def test_zero(self):
        self.assertEqual(humanize_secs(0), "0h 0m 0s")

    def test_normal(self):
        self.assertEqual(humanize_secs(3723), "1h 2m 3s")

    def test_large(self):
        self.assertEqual(humanize_secs(86399), "23h 59m 59s")

    def test_only_minutes(self):
        self.assertEqual(humanize_secs(300), "0h 5m 0s")

    def test_negative(self):
        with self.assertRaises(ValueError):
            humanize_secs(-1)


class TestIsLeap(unittest.TestCase):
    def test_400_year(self):
        self.assertTrue(is_leap(2000))

    def test_100_year_not_400(self):
        self.assertFalse(is_leap(1900))

    def test_divisible_by_4(self):
        self.assertTrue(is_leap(2024))

    def test_not_divisible_by_4(self):
        self.assertFalse(is_leap(2023))

    def test_zero(self):
        with self.assertRaises(ValueError):
            is_leap(0)

    def test_negative(self):
        with self.assertRaises(ValueError):
